import { RuleTester } from 'eslint';
import { unsupportedHtmlElements } from "../../rules/no-html-elements.js";
import { languageOptions } from "../../runtime.js";
const ruleTester = new RuleTester({
    languageOptions: {
        ...languageOptions,
        parserOptions: {
            ecmaFeatures: {
                jsx: true,
            },
        },
    },
});
const simpleValidElement = `
function App() {
  return <Button>Click Me</Button>
};
`;
const nestedValidElements = `
function App() {
  return (
    <Box>
      <Text>A Headline</Text>
      <Button>Click Me</Button>
    </Box>
  );
};
`;
const reactFragmentValidElements = `
function App() {
  return (
    <>
      <Text>Fragment Text</Text>
      <Button>Click Me</Button>
    </>
  );
};
`;
const customDivValidElement = `
function Div() {
  return <Box>Custom Div</Box>
};

function App() {
  return <Div />;
};
`;
const simpleInvalidElement = `
function App() {
  return <div>Invalid Element</div>;
};
`;
const nestedInvalidElements = `
function App() {
  return (
    <div>
      <h1>Invalid Header</h1>
      <p>Invalid paragraph content <a href="#">with a link</a> and a <span style="font-weight: bold;">span tag for extra styling.</span></p>
      <button>Click Me</button>
    </div>
  );
};
`;
const selfClosingInvalidElement = `
function App() {
  return <img src="image.png" alt="Invalid Image" />;
};
`;
describe('no-html-elements', () => {
    ruleTester.run('no-html-elements', unsupportedHtmlElements, {
        valid: [
            {
                name: 'allows simple valid UI Extension components',
                code: simpleValidElement,
            },
            {
                name: 'allows nested valid UI Extension components',
                code: nestedValidElements,
            },
            {
                name: 'allows React Fragment syntax',
                code: reactFragmentValidElements,
            },
            {
                name: 'allows PascalCase component names that match HTML element names',
                code: customDivValidElement,
            },
        ],
        invalid: [
            {
                name: 'reports error for simple HTML element',
                code: simpleInvalidElement,
                errors: [
                    {
                        messageId: 'htmlNotSupported',
                        data: { elementName: 'div' },
                    },
                ],
            },
            {
                name: 'reports errors for multiple nested HTML elements',
                code: nestedInvalidElements,
                errors: [
                    {
                        messageId: 'htmlNotSupported',
                        data: { elementName: 'div' },
                    },
                    {
                        messageId: 'htmlNotSupported',
                        data: { elementName: 'h1' },
                    },
                    {
                        messageId: 'htmlNotSupported',
                        data: { elementName: 'p' },
                    },
                    {
                        messageId: 'htmlNotSupported',
                        data: { elementName: 'a' },
                    },
                    {
                        messageId: 'htmlNotSupported',
                        data: { elementName: 'span' },
                    },
                    {
                        messageId: 'htmlNotSupported',
                        data: { elementName: 'button' },
                    },
                ],
            },
            {
                name: 'reports error for self-closing HTML elements',
                code: selfClosingInvalidElement,
                errors: [
                    {
                        messageId: 'htmlNotSupported',
                        data: { elementName: 'img' },
                    },
                ],
            },
        ],
    });
});
